arguments.argument:
if dashDuration=0 and bCanTakeDamage=true
{
  if bCanDash=1
  {
    if movePhase=0 //Stationary
    {
      if hspeed=0 and vspeed=0 and dashEnergy>=2000
      {
        hspeed=choose(-6,-4,4,6); vspeed=choose(-6-4,4,6)
        dashEnergy-=2000
        dashDuration=10
      }
      else {event_inherited()}
    }
  }
  else {event_inherited()}
}
